module top_module(
    input [3:0] a,
    input [3:0] b,
    output reg not_equal,
    output reg greater,
    output reg less
);always @(*) begin
        if (a == b) begin
            not_equal = 1;
            greater = 0;
            less = 0;
        end else if (a > b) begin
            not_equal = 0;
            greater = 1;
            less = 0;
        end else begin
            not_equal = 0;
            greater = 0;
            less = 1;
        end
    end

endmodule
